/**
 * Sequential color scale for risk values (yellow → red)
 */
export const RISK_COLORS = [
  '#ffffcc', // very low
  '#ffeda0',
  '#fed976',
  '#feb24c',
  '#fd8d3c',
  '#fc4e2a',
  '#e31a1c', // extreme
] as const;

/**
 * Get color from sequential scale based on normalized value (0-1)
 */
export function getRiskColor(value: number, min: number, max: number): string {
  if (max === min) return RISK_COLORS[0];
  const normalized = (value - min) / (max - min);
  const idx = Math.min(Math.floor(normalized * RISK_COLORS.length), RISK_COLORS.length - 1);
  return RISK_COLORS[Math.max(0, idx)];
}

/**
 * Format a large number for display
 * e.g., 1234567 → "$1.23M", 456 → "456", 1234567890 → "$1.23B"
 */
export function formatRiskValue(value: number, mode: RiskMode): string {
  if (value === 0) return '0';

  if (mode === 'Dmg') {
    // Monetary values
    if (value >= 1e9) return `$${(value / 1e9).toFixed(1)}B`;
    if (value >= 1e6) return `$${(value / 1e6).toFixed(1)}M`;
    if (value >= 1e3) return `$${(value / 1e3).toFixed(0)}K`;
    return `$${value.toFixed(0)}`;
  }

  // Area/count/population values
  if (value >= 1e9) return `${(value / 1e9).toFixed(1)}B`;
  if (value >= 1e6) return `${(value / 1e6).toFixed(1)}M`;
  if (value >= 1e3) return `${(value / 1e3).toFixed(0)}K`;
  return value.toFixed(0);
}

/**
 * Format value with full precision for tooltips and tables
 */
export function formatRiskValueFull(value: number, mode: RiskMode): string {
  if (value === 0) return mode === 'Dmg' ? '$0' : '0';

  if (mode === 'Dmg') {
    if (value >= 1e9) return `$${(value / 1e9).toFixed(2)}B`;
    if (value >= 1e6) return `$${(value / 1e6).toFixed(1)}M`;
    if (value >= 1e3) return `$${(value / 1e3).toFixed(0)}K`;
    return `$${value.toFixed(0)}`;
  }

  if (mode === 'Pop') {
    return Math.round(value).toLocaleString();
  }

  if (value >= 1e9) return `${(value / 1e9).toFixed(2)}B`;
  if (value >= 1e6) return `${(value / 1e6).toFixed(1)}M`;
  if (value >= 1e3) return `${(value / 1e3).toFixed(0)}K`;
  return value.toFixed(0);
}

/**
 * Get unit label for a mode
 */
export function getRiskUnitLabel(mode: RiskMode): string {
  switch (mode) {
    case 'Exp': return 'Area (ha / sqm)';
    case 'Vul': return 'Vulnerable Area (ha / sqm)';
    case 'Dmg': return 'Economic Damage (USD)';
    case 'Pop': return 'Estimated Fatalities';
  }
}

/**
 * Build scenario key from components
 */
export function buildScenarioKey(
  returnPeriod: number,
  climate: 'present' | 'future',
  maintenance: 'breaches' | 'redcapacity' | 'perfect'
): ScenarioKey {
  return `${returnPeriod}_${climate}_${maintenance}`;
}

