/** Result of EAD calculation for one climate × maintenance × region */
export type EadResult = {
  climate: 'present' | 'future';
  maintenance: 'breaches' | 'redcapacity' | 'perfect';
  region: string;
  ead: Record<AssetSubKey, number>;
  eadTotal: number;
};

/** Result of Expected Annual Population Affected (EAPA) calculation */
export type EapaResult = {
  climate: 'present' | 'future';
  maintenance: 'breaches' | 'redcapacity' | 'perfect';
  region: string;
  eapa: number;
  byDistrict?: Record<DistrictName, number>;
};

/**
 * Calculate Expected Annual Damage using trapezoidal integration.
 *
 * EAD = Σ 0.5 × (Dᵢ + Dᵢ₊₁) × |1/RPᵢ - 1/RPᵢ₊₁|
 *
 * @param damages - Array of { returnPeriod, damage } sorted by returnPeriod ascending
 */
export function calculateEad(damages: { returnPeriod: number; damage: number }[]): number {
  if (damages.length < 2) return 0;
  let ead = 0;
  for (let i = 0; i < damages.length - 1; i++) {
    const freqLeft = 1 / damages[i].returnPeriod;
    const freqRight = 1 / damages[i + 1].returnPeriod;
    ead += 0.5 * (damages[i].damage + damages[i + 1].damage) * Math.abs(freqLeft - freqRight);
  }
  return ead;
}

/**
 * Calculate TOTAL risk data by summing all districts for a given scenario and mode.
 * This ensures TOTAL reflects only the active districts (7, not 9).
 */
export function calculateTotalRisk(
  data: RiskJsonData,
  scenarioKey: ScenarioKey,
  mode: RiskMode
): RegionRiskData | null {
  const scenarioData = data.data[scenarioKey];
  if (!scenarioData) return null;

  // Sum all districts for all 11 assets
  const total: RegionRiskData = {
    crop: 0,
    buildLow56: 0,
    buildLow44: 0,
    buildHigh: 0,
    telecom: 0,
    electric: 0,
    railways: 0,
    hospitals: 0,
    bhu: 0,
    schools: 0,
    roads: 0,
  };

  for (const district of DISTRICTS) {
    const districtData = scenarioData[district]?.[mode];
    if (!districtData) continue;

    total.crop += districtData.crop ?? 0;
    total.buildLow56 += districtData.buildLow56 ?? 0;
    total.buildLow44 += districtData.buildLow44 ?? 0;
    total.buildHigh += districtData.buildHigh ?? 0;
    total.telecom += districtData.telecom ?? 0;
    total.electric += districtData.electric ?? 0;
    total.railways += districtData.railways ?? 0;
    total.hospitals += districtData.hospitals ?? 0;
    total.bhu += districtData.bhu ?? 0;
    total.schools += districtData.schools ?? 0;
    total.roads += districtData.roads ?? 0;
  }

  return total;
}
